#nullable enable // autogenerated

using System;
using System.Linq;
using MVZ2.GameContent.Grids;
using MVZ2Logic.Grids;
using PVZEngine.Entities;
using PVZEngine.Grids;

namespace MVZ2.Vanilla.Grids
{
    public static class VanillaGridExt
    {

        #region 层级
        public static Entity? GetCarrierEntity(this LawnGrid grid)
        {
            return grid.GetLayerEntity(VanillaGridLayers.carrier);
        }
        public static Entity? GetMainEntity(this LawnGrid grid)
        {
            return grid.GetLayerEntity(VanillaGridLayers.main);
        }
        public static Entity? GetToolEntity(this LawnGrid grid)
        {
            return grid.GetLayerEntity(VanillaGridLayers.tool);
        }
        public static Entity? GetProtectorEntity(this LawnGrid grid)
        {
            return grid.GetLayerEntity(VanillaGridLayers.protector);
        }
        #endregion

        #region 导电
        public static bool IsConductive(this LawnGrid grid)
        {
            if (grid.IsWater())
                return true;
            if (grid.IsWet())
                return true;
            return false;
        }
        #endregion

        #region 获取指向实体
        public static Entity? FindPointerTargetEntity(this LawnGrid grid, float pointerPosition, Predicate<Entity> predicate, out float rangeMin, out float rangeMax)
        {
            var protector = grid.GetProtectorEntity();
            var protectedLayers = VanillaGridLayers.protectedLayers;
            var hasProtector = protector != null;

            var protectedEntities = protectedLayers.Select(t => grid.GetLayerEntity(t)).OfType<Entity>();
            var hasMain = protectedEntities.Count() > 0;
            var validMain = protectedEntities.FirstOrDefault(t => predicate(t));

            var canUseOnProtector = protector != null && predicate(protector);
            var canUseOnMain = validMain != null;

            rangeMin = 0;
            rangeMax = 1;

            if (canUseOnProtector && canUseOnMain)
            {
                // 两者都可以使用，根据 pointerPosition 选择
                if (pointerPosition < 0.5f)
                {
                    // 指向下方，选择保护层
                    rangeMax = 0.5f;
                    return protector;
                }
                else
                {
                    // 指向上方，选择主要层
                    rangeMin = 0.5f;
                    return validMain;
                }
            }

            if (canUseOnProtector)
            {
                // 只能使用保护层
                if (hasMain)
                {
                    // 存在主要层但不可用
                    rangeMax = 0.5f;
                }
                return protector;
            }

            if (canUseOnMain)
            {
                // 只能使用主要层
                if (hasProtector)
                {
                    // 存在保护层但不可用
                    rangeMin = 0.5f;
                }
                return validMain;
            }
            return null;
        }
        #endregion
        public static int GetGridModelType(this LawnGrid grid)
        {
            if (grid.GetSlope() > 0)
            {
                return VanillaGridModelTypes.TYPE_SLOPE;
            }
            if (grid.Definition.IsCloud())
            {
                return VanillaGridModelTypes.TYPE_CLOUD;
            }
            if (grid.Definition.IsWater())
            {
                return VanillaGridModelTypes.TYPE_WATER;
            }
            return VanillaGridModelTypes.TYPE_NORMAL;
        }
    }
}
